import{_ as i,o as l,c as t,a4 as a}from"./chunks/framework.DkKDtR5x.js";const m=JSON.parse('{"title":"Dashboard AI Week","description":"","frontmatter":{},"headers":[],"relativePath":"work/dashboard-ai-week.md","filePath":"work/dashboard-ai-week.md"}'),o={name:"work/dashboard-ai-week.md"};function s(n,e,r,d,c,h){return l(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="dashboard-ai-week" tabindex="-1">Dashboard AI Week <a class="header-anchor" href="#dashboard-ai-week" aria-label="Permalink to “Dashboard AI Week”">​</a></h1><ul><li>Google doc <a href="https://docs.google.com/document/d/1Y0A46I6VQLSi1JnE68S5KzHIGBT1ixP8l492AR1d5Vg/edit?tab=t.p03jtmvacv2w" target="_blank">here</a></li><li>📺 <a href="https://www.youtube.com/watch?v=QcxL0SXILC4" target="_blank">What are Skills, Agents, Prompts, Instructions and how to use them?</a></li><li>AI DLC <ul><li><a href="https://www.youtube.com/watch?v=1HNUH6j5t4A" target="_blank">AWS re:Invent 2025 - Introducing AI driven development lifecycle (AI-DLC) (DVT214)</a></li><li><a href="https://www.youtube.com/live/5kUb_IZdlB8" target="_blank">Build Smarter with AI-Driven Development Life Cycle (AI-DLC)</a></li></ul></li><li>Harnesses in AI <ul><li><a href="https://www.youtube.com/watch?v=C_GG5g38vLU" target="_blank">Harnesses in AI: A Deep Dive — Tejas Kumar, IBM</a></li><li><a href="https://www.youtube.com/watch?v=sFHXYv7ANkc" target="_blank">What Is AI Harness Exactly?</a></li></ul></li></ul><h1 id="what-are-skills-agents-prompts-instructions-and-how-to-use-them" tabindex="-1">What are Skills, Agents, Prompts, Instructions and how to use them? <a class="header-anchor" href="#what-are-skills-agents-prompts-instructions-and-how-to-use-them" aria-label="Permalink to “What are Skills, Agents, Prompts, Instructions and how to use them?”">​</a></h1><ul><li>A prompt is a one-time chat message.</li><li>An instruction is a permanent rule for a project.</li><li>A skill is a tool the AI loads only when needed.</li></ul><h2 id="agents-md" tabindex="-1">AGENTS.md <a class="header-anchor" href="#agents-md" aria-label="Permalink to “AGENTS.md”">​</a></h2><ul><li>inspired by CLAUDE.md from Anthropic</li><li>Instead of having md files for each vendor</li><li><code>.github/copilot-instructions.md</code> used for github copilot as your PR code reviewer</li><li><code>/init</code></li><li>AGENTS.md sections <ul><li>Architecture overview</li><li>Dos and Donts</li><li>Comments</li></ul></li><li>Better to have AGENTS.md for each project module as well</li></ul><h2 id="custom-agents" tabindex="-1">Custom Agents <a class="header-anchor" href="#custom-agents" aria-label="Permalink to “Custom Agents”">​</a></h2><ul><li><code>agents</code> folder</li><li>They are like specialized colleagues, can be given some personality</li><li>Orchestrator Agent, Planner Agent and Coder Agent <ul><li>cleaner context memory</li></ul></li><li>.github/agents, uses tools</li><li><a href="https://github.com/github/awesome-copilot" target="_blank">github/awesome-copilot</a></li><li>SubAgents vs Agent Teams <ul><li>Subagent reports back to orchestrator</li><li>Agent team communicate with other agents</li></ul></li></ul><p><img src="https://pbs.twimg.com/media/HAbME1jacAElNbd?format=jpg&amp;name=medium" alt="image"></p><h2 id="hooks" tabindex="-1">Hooks <a class="header-anchor" href="#hooks" aria-label="Permalink to “Hooks”">​</a></h2><ul><li><code>hooks</code> folder</li><li>Hooks run before agents are loaded</li><li>They have lifecycle methods like sessionStart, sessionEnd, userPromptSubmitted etc</li><li>Try some hooks from awesome-copilot</li><li>example : secret scanner and governance-audit</li><li>Show agent logs in vscode, <code>ask a questions in chat</code> -&gt; <code>setting (gear icon) in chat</code> -&gt; <code>agent logs</code><ul><li>Loaded instructions -&gt; skills -&gt; hooks -&gt; agents</li></ul></li></ul><h2 id="instructions" tabindex="-1">Instructions <a class="header-anchor" href="#instructions" aria-label="Permalink to “Instructions”">​</a></h2><ul><li><code>instructions</code> folder</li><li>has applyTo liquid attribute</li><li>mention in main AGENTS.md when to refer which instruction</li><li>A global rule file that stays active across the whole project. example use java 11 and gradle instead of maven</li></ul><h2 id="prompts" tabindex="-1">Prompts <a class="header-anchor" href="#prompts" aria-label="Permalink to “Prompts”">​</a></h2><ul><li><code>prompts</code> folder</li><li>use <code>/explain-code</code> for <code>.github/prompts/explain-code.prompt.md</code></li><li>example: brief overview, step-by-step breakdown, key concepts and terms, common use cases</li></ul><h2 id="skills" tabindex="-1">Skills <a class="header-anchor" href="#skills" aria-label="Permalink to “Skills”">​</a></h2><ul><li><code>skills</code> folder</li><li>Folder based capability packages with a required SKILL.md that are loaded by an Agent on-demand</li><li><code>.github/skills/breakdown-plan/SKILLS.md</code> will create some docs</li><li>invokable</li><li>Persistent, modular files loaded only when triggered.</li></ul><h2 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to “Workflow”">​</a></h2><ul><li><code>workflow</code> folder</li><li>Copilot coding agent works anonymously in a Github actions-powered env to complete development tasks and creates pull requests with the result.</li><li>daily-issues-report</li></ul><h1 id="ai-dlc" tabindex="-1">AI-DLC <a class="header-anchor" href="#ai-dlc" aria-label="Permalink to “AI-DLC”">​</a></h1><ul><li>AI driven development lifecycle (AI-DLC) <ul><li><code>AI Creates Plan</code> -&gt; <code>Human Verify Plan</code> -&gt; <code>AI refines Plan</code> -&gt; <code>AI executes plan</code> -&gt; <code>Human verify outcome</code></li></ul></li><li>Approach 1 : AI Managed <ul><li>AI autonomously builds and maintains software with leasat ot zero human involvement</li></ul></li><li>Approach 2 : AI Assisted <ul><li>Developers still perform the intellectual heavy lifting and apply AI in narrow tasks</li></ul></li><li>Steps <ul><li>Inception (Mob Elaboration) <ul><li>Build Context on existing codes</li><li>Elaborate intent with user stories.</li><li>Plan with units of work.</li></ul></li><li>Construction (Mob Construction) <ul><li>Domain model (component model)</li><li>Add architectural components</li><li>genrate code and test</li></ul></li><li>Operation (CICD) <ul><li>Deploy in Prod with IaaC</li><li>Manage incidents - AI first, Fast feedback to dev</li></ul></li></ul></li><li>Avoid vibe coding <ul><li>Can you debug every line of code?</li><li>Do you understand the code end-to-end?</li></ul></li><li>Start with small simple tasks <ul><li>No complex task that may succeed</li><li>Start by vreating simple tasks that always succeed</li><li>Continue breaking into the specific functions, files or flows</li></ul></li><li>Clear context, keep context focused</li><li>Ask AI to mimic existing code examples rather than complex instructions</li><li>semantics ratio in the tokens <ul><li>good : <code>refactor using builder pattern</code></li><li>bad : <code>ability to build complex object blah blah</code></li></ul></li><li>Beware fo Model&#39;s stale training dataset</li><li>Keep number of MCP tools minimal <ul><li>required MCP uses context window or something else</li></ul></li><li>Old measuring metrics don&#39;t work anymore like lines of code</li><li>Is re-writing faster than patching</li><li>Example : Fast API to support QUERY http method <ul><li><code>.amazonq</code> folder had AI-DLC rules</li><li>it outputs aidlc-docs folder based on the instructions <ul><li>rule had inception/reverse-engineering folder</li></ul></li></ul></li><li>🔗 <a href="https://github.com/awslabs/aidlc-workflows/blob/main/aidlc-rules/aws-aidlc-rules/core-workflow.md" target="_blank">github aidlc core-workflow</a></li></ul><h1 id="harnesses-in-ai" tabindex="-1">Harnesses in AI <a class="header-anchor" href="#harnesses-in-ai" aria-label="Permalink to “Harnesses in AI”">​</a></h1><ul><li>Why? Reliability</li><li>An AI harness (also called an agent harness) is the software infrastructure, tools, and rules wrapped around an AI model to make it work reliably in the real world.</li><li>While a raw Artificial Intelligence model is just a &quot;text-in, text-out&quot; brain, it cannot actually perform tasks on its own. The harness is the system that connects that brain to the outside world, giving it tools, memory, and safety guardrails.</li><li><code>Agent = Model + Harness</code></li><li>Six Core Layers of an AI Harness <ul><li>The Execution Loop: It keeps the AI running in a continuous loop (Observe ➔ Decide ➔ Act ➔ Verify) until the job is fully done.</li><li>Tool Management: It gives the AI the ability to click buttons, search the web, read files, and run code.</li><li>Context Engineering: It filters information so the AI only sees what is relevant, preventing it from getting overwhelmed.</li><li>Persistence (Memory): It saves the AI’s progress to a database so it does not forget what it was doing if the system restarts.</li><li>Verification: It automatically checks the AI&#39;s work—like running a code test—to catch mistakes before a human sees them.</li><li>Constraints (Guardrails): It blocks the AI from taking dangerous actions, like deleting important company files.</li></ul></li><li>Agent Harness <ul><li>Tool Registry</li><li>Model</li><li>Context Management</li><li>Guardrails</li><li>Agent Loops</li><li>Verify</li></ul></li><li>Example : Use ChatFPT 3.5 and harness it</li><li></li></ul>',23)])])}const p=i(o,[["render",s]]);export{m as __pageData,p as default};
